<h2>Daily Attendance</h2><form class="card form-grid" method="post"><label>Student<select name="student_id"><?php foreach ($lookups->students() as $s): ?><option value="<?= e($s['id']) ?>" data-class="<?= e($s['class_id']) ?>"><?= e($s['admission_no'].' '.$s['first_name'].' '.$s['last_name']) ?></option><?php endforeach; ?></select></label><label>Class ID<input type="number" name="class_id" required></label><label>Date<input type="date" name="attendance_date" value="<?= date('Y-m-d') ?>" required></label><label>Status<select name="status"><option value="present">Present</option><option value="absent">Absent</option><option value="late">Late</option><option value="excused">Excused</option></select></label><label class="wide">Note<input name="note"></label><button>Save Attendance</button></form>
